def get_with_lock(key, ttl=300):
    val = r.get(key)
    if val is not None:
        return val
    # Only one worker rebuilds; others wait or serve stale
    if r.set(f"lock:{key}", "1", nx=True, ex=10):
        val = rebuild_from_db(key)
        r.set(key, val, ex=ttl)
        r.delete(f"lock:{key}")
    return val
